parameters.jsCode:
const html = $json.html;
const fileName = 'index.html';

const binaryData = Buffer.from(html).toString('base64');

return {
  json: {
    filename: $json.filename,
  },
  binary: {
    data: {
      data: binaryData,
      mimeType: 'text/html',
      fileName: fileName,
    },
  },
};

const markdown = $json.output.reportContent;

function mdToHtml(md) {
  return md
    .replace(/^### (.*)$/gm, '<h3>$1</h3>')
    .replace(/^## (.*)$/gm, '<h2>$1</h2>')
    .replace(/^# (.*)$/gm, '<h1>$1</h1>')
    .replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>')
    .replace(/^- (.*)$/gm, '<li>$1</li>')
    .replace(/\n/g, '<br>');
}

return {
  json: {
    ...$json,
    htmlContent: mdToHtml(markdown),
  },
};
